import { Choice } from '../core/PkiBase.js';
import { RDNSequence } from './RDNSequence.js';
export const Name = Choice('Name', {
    RDNSequence,
    fromAsn1(asn1) {
        return RDNSequence.fromAsn1(asn1);
    },
    parse(humanString) {
        return RDNSequence.parse(humanString);
    },
});
